// Phase 1: Setup Custom Fields
// Mode: runOnceForAllItems

const APOLLO_API_KEY = $('Set Config').item.json.apollo_api_key;
const BASE_URL = 'https://api.apollo.io/api/v1';

const ACCOUNT_FIELDS = [
  { label: 'Lead Score', field_type: 'number' },
  { label: 'Has Website', field_type: 'boolean' },
  { label: 'Has Online Booking', field_type: 'boolean' },
  { label: 'Booking Platform', field_type: 'text_field' },
  { label: 'Has Paid Ads', field_type: 'boolean' },
  { label: 'On Groupon', field_type: 'boolean' },
  { label: 'On Yelp', field_type: 'boolean' },
  { label: 'Google Review Count', field_type: 'number' },
  { label: 'Google Rating', field_type: 'number' },
  { label: 'Estimated Size', field_type: 'text_field' },
  { label: 'Enrichment Status', field_type: 'text_field' },
  { label: 'Category', field_type: 'text_field' },
  { label: 'VerveLabs Run Tag', field_type: 'text_field' },
];

const CONTACT_FIELDS = [
  { label: 'Cultural Affinity', field_type: 'text_field' },
  { label: 'Is Owner', field_type: 'boolean' },
  { label: 'Contact Role', field_type: 'text_field' },
  { label: 'Contact Source', field_type: 'text_field' },
  { label: 'VerveLabs Run Tag', field_type: 'text_field' },
];

// Fetch existing custom fields
let existingFields = [];
try {
  const res = await fetch(`${BASE_URL}/fields`, {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': APOLLO_API_KEY,
      'Cache-Control': 'no-cache'
    }
  });
  const data = await res.json();
  existingFields = data.fields || [];
} catch (e) {
  // If listing fails, proceed anyway - creates are idempotent
  console.log('Could not list existing fields:', e.message);
}

const existingLabels = new Set(
  existingFields.map(f => f.label?.toLowerCase())
);

const results = { created: [], skipped: [], errors: [] };

// Create account custom fields
for (const field of ACCOUNT_FIELDS) {
  if (existingLabels.has(field.label.toLowerCase())) {
    results.skipped.push(field.label);
    continue;
  }
  try {
    const res = await fetch(`${BASE_URL}/fields`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': APOLLO_API_KEY
      },
      body: JSON.stringify({
        label: field.label,
        field_type: field.field_type,
        modality: 'account'
      })
    });
    if (res.ok) {
      results.created.push(field.label);
    } else {
      const errData = await res.json();
      results.errors.push(
        `${field.label}: ${JSON.stringify(errData)}`
      );
    }
    // Rate limit: wait 700ms between calls
    await new Promise(r => setTimeout(r, 700));
  } catch (e) {
    results.errors.push(`${field.label}: ${e.message}`);
  }
}

// Create contact custom fields
for (const field of CONTACT_FIELDS) {
  if (existingLabels.has(field.label.toLowerCase())) {
    results.skipped.push(field.label);
    continue;
  }
  try {
    const res = await fetch(`${BASE_URL}/fields`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': APOLLO_API_KEY
      },
      body: JSON.stringify({
        label: field.label,
        field_type: field.field_type,
        modality: 'contact'
      })
    });
    if (res.ok) {
      results.created.push(field.label);
    } else {
      const errData = await res.json();
      results.errors.push(
        `${field.label}: ${JSON.stringify(errData)}`
      );
    }
    await new Promise(r => setTimeout(r, 700));
  } catch (e) {
    results.errors.push(`${field.label}: ${e.message}`);
  }
}

return [{
  json: {
    phase: 'custom_fields_setup',
    ...results
  }
}];

// Phase 2: Fetch Unsynced Data from Supabase
// Mode: runOnceForAllItems

const SUPABASE_URL = $('Set Config').item.json.supabase_url;
const SUPABASE_KEY = $('Set Config').item.json.supabase_service_key;
const RUN_TAG = $('Set Config').item.json.run_tag;

const headers = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// Fetch companies needing sync
// Condition: fully_enriched AND (never synced OR re-enriched since last sync)
const companiesRes = await fetch(
  `${SUPABASE_URL}/rest/v1/companies?enrichment_status=eq.fully_enriched&or=(apollo_synced_at.is.null,enriched_at.gt.apollo_synced_at)&select=*&order=city,name&limit=500`,
  { headers }
);
const companies = await companiesRes.json();

if (!companies || companies.length === 0) {
  return [{ json: { phase: 'fetch', companies: [], message: 'No unsynced companies found' } }];
}

// Fetch contacts for these companies
const companyIds = companies.map(c => c.id);
const contactsRes = await fetch(
  `${SUPABASE_URL}/rest/v1/contacts?company_id=in.(${companyIds.join(',')})&select=*`,
  { headers }
);
const contacts = await contactsRes.json();

// Group contacts by company_id
const contactsByCompany = {};
for (const contact of contacts) {
  if (!contactsByCompany[contact.company_id]) {
    contactsByCompany[contact.company_id] = [];
  }
  contactsByCompany[contact.company_id].push(contact);
}

// Emit one item per company with its contacts attached
return companies.map(company => ({
  json: {
    company,
    contacts: contactsByCompany[company.id] || [],
    run_tag: RUN_TAG
  }
}));

// Phase 3: Upsert Account in Apollo
// Mode: runOnceForEachItem

const APOLLO_API_KEY = $('Set Config').item.json.apollo_api_key;
const BASE_URL = 'https://api.apollo.io/api/v1';
const company = $input.item.json.company;
const contacts = $input.item.json.contacts;
const run_tag = $input.item.json.run_tag;

const apiHeaders = {
  'Content-Type': 'application/json',
  'x-api-key': APOLLO_API_KEY,
  'Cache-Control': 'no-cache'
};

// Build custom fields payload
const customFields = {
  'Lead Score': company.lead_score || 0,
  'Has Website': company.has_website || false,
  'Has Online Booking': company.has_online_booking || false,
  'Booking Platform': company.booking_platform || '',
  'Has Paid Ads': company.has_paid_ads || false,
  'On Groupon': company.on_groupon || false,
  'On Yelp': company.on_yelp || false,
  'Google Review Count': company.google_review_count || 0,
  'Google Rating': parseFloat(company.google_rating) || 0,
  'Estimated Size': company.estimated_size || '',
  'Enrichment Status': company.enrichment_status || '',
  'Category': company.category || '',
  'VerveLabs Run Tag': run_tag
};

let apolloAccountId = company.apollo_account_id;
let action = 'skipped';

try {
  // Step 1: Search for existing account by domain
  if (company.domain && !apolloAccountId) {
    const searchRes = await fetch(
      `${BASE_URL}/accounts/search`,
      {
        method: 'POST',
        headers: apiHeaders,
        body: JSON.stringify({
          q_organization_domains: company.domain,
          page: 1,
          per_page: 1
        })
      }
    );
    const searchData = await searchRes.json();
    if (searchData.accounts && searchData.accounts.length > 0) {
      apolloAccountId = searchData.accounts[0].id;
    }
    await new Promise(r => setTimeout(r, 700));
  }

  // Step 2: Build account payload
  const accountPayload = {
    name: company.name,
    domain: company.domain || undefined,
    phone_number: company.phone || undefined,
    raw_address: company.address || undefined,
    city: company.city || undefined,
    state: company.state || undefined,
    country: company.country || 'US',
    website_url: company.domain
      ? `https://${company.domain}` : undefined,
    custom_fields: customFields
  };

  // Step 3: Update or Create
  if (apolloAccountId) {
    // UPDATE existing account
    const updateRes = await fetch(
      `${BASE_URL}/accounts/${apolloAccountId}`,
      {
        method: 'PATCH',
        headers: apiHeaders,
        body: JSON.stringify(accountPayload)
      }
    );
    if (updateRes.ok) {
      action = 'updated';
    } else {
      const err = await updateRes.json();
      action = `update_error: ${JSON.stringify(err)}`;
    }
  } else {
    // CREATE new account
    const createRes = await fetch(
      `${BASE_URL}/accounts`,
      {
        method: 'POST',
        headers: apiHeaders,
        body: JSON.stringify(accountPayload)
      }
    );
    const createData = await createRes.json();
    if (createRes.ok && createData.account) {
      apolloAccountId = createData.account.id;
      action = 'created';
    } else {
      action = `create_error: ${JSON.stringify(createData)}`;
    }
  }

  // Rate limit pause
  await new Promise(r => setTimeout(r, 700));

} catch (e) {
  action = `exception: ${e.message}`;
}

return {
  json: {
    company,
    contacts,
    run_tag,
    apollo_account_id: apolloAccountId,
    account_action: action
  }
};

// Phase 4: Upsert Contacts in Apollo
// Mode: runOnceForEachItem

const APOLLO_API_KEY = $('Set Config').item.json.apollo_api_key;
const BASE_URL = 'https://api.apollo.io/api/v1';
const company = $input.item.json.company;
const contacts = $input.item.json.contacts;
const run_tag = $input.item.json.run_tag;
const apolloAccountId = $input.item.json.apollo_account_id;

const apiHeaders = {
  'Content-Type': 'application/json',
  'x-api-key': APOLLO_API_KEY,
  'Cache-Control': 'no-cache'
};

const contactResults = [];

for (const contact of contacts) {
  try {
    let apolloContactId = contact.apollo_contact_id;
    let action = 'skipped';

    const contactCustomFields = {
      'Cultural Affinity': contact.cultural_affinity || '',
      'Is Owner': contact.is_owner || false,
      'Contact Role': contact.role || 'unknown',
      'Contact Source': contact.source || '',
      'VerveLabs Run Tag': run_tag
    };

    const contactPayload = {
      first_name: contact.first_name || '',
      last_name: contact.last_name || '',
      organization_name: company.name,
      account_id: apolloAccountId || undefined,
      title: contact.role === 'owner' ? 'Owner'
        : contact.role === 'manager' ? 'Manager'
        : contact.role === 'practitioner'
          ? 'Practitioner' : undefined,
      email: contact.email_business
        || contact.email_personal || undefined,
      direct_phone: contact.phone_direct || undefined,
      corporate_phone: company.phone || undefined,
      linkedin_url: contact.linkedin_url || undefined,
      present_raw_address: contact.location
        || company.address || undefined,
      custom_fields: contactCustomFields
    };

    if (apolloContactId) {
      // UPDATE existing contact
      const updateRes = await fetch(
        `${BASE_URL}/contacts/${apolloContactId}`,
        {
          method: 'PATCH',
          headers: apiHeaders,
          body: JSON.stringify(contactPayload)
        }
      );
      action = updateRes.ok ? 'updated' : 'update_error';
    } else {
      // CREATE with dedup enabled
      contactPayload.run_dedupe = true;
      const createRes = await fetch(
        `${BASE_URL}/contacts`,
        {
          method: 'POST',
          headers: apiHeaders,
          body: JSON.stringify(contactPayload)
        }
      );
      const createData = await createRes.json();
      if (createRes.ok && createData.contact) {
        apolloContactId = createData.contact.id;
        action = 'created';
      } else {
        action = `create_error: ${JSON.stringify(createData)}`;
      }
    }

    contactResults.push({
      supabase_contact_id: contact.id,
      apollo_contact_id: apolloContactId,
      name: `${contact.first_name} ${contact.last_name}`,
      action
    });

    // Rate limit: 700ms between API calls
    await new Promise(r => setTimeout(r, 700));

  } catch (e) {
    contactResults.push({
      supabase_contact_id: contact.id,
      name: `${contact.first_name} ${contact.last_name}`,
      action: `exception: ${e.message}`
    });
  }
}

return {
  json: {
    company_id: company.id,
    company_name: company.name,
    apollo_account_id: apolloAccountId,
    account_action: $input.item.json.account_action,
    contact_results: contactResults
  }
};

// Phase 5: Mark Synced in Supabase
// Mode: runOnceForEachItem

const SUPABASE_URL = $('Set Config').item.json.supabase_url;
const SUPABASE_KEY = $('Set Config').item.json.supabase_service_key;
const item = $input.item.json;
const now = new Date().toISOString();

const headers = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

const results = { company: null, contacts: [] };

try {
  // Update company apollo_account_id + apollo_synced_at
  if (item.apollo_account_id) {
    const compRes = await fetch(
      `${SUPABASE_URL}/rest/v1/companies?id=eq.${item.company_id}`,
      {
        method: 'PATCH',
        headers,
        body: JSON.stringify({
          apollo_account_id: item.apollo_account_id,
          apollo_synced_at: now
        })
      }
    );
    results.company = compRes.ok ? 'synced' : 'error';
  }

  // Update each contact's apollo_contact_id + apollo_synced_at
  for (const cr of (item.contact_results || [])) {
    if (cr.apollo_contact_id && cr.supabase_contact_id) {
      const ctRes = await fetch(
        `${SUPABASE_URL}/rest/v1/contacts?id=eq.${cr.supabase_contact_id}`,
        {
          method: 'PATCH',
          headers,
          body: JSON.stringify({
            apollo_contact_id: cr.apollo_contact_id,
            apollo_synced_at: now
          })
        }
      );
      results.contacts.push({
        id: cr.supabase_contact_id,
        status: ctRes.ok ? 'synced' : 'error'
      });
    }
  }
} catch (e) {
  results.error = e.message;
}

return {
  json: {
    company_id: item.company_id,
    company_name: item.company_name,
    apollo_account_id: item.apollo_account_id,
    account_action: item.account_action,
    contact_results: item.contact_results,
    sync_results: results
  }
};

// Log Summary — aggregate sync results from all batches
// Mode: runOnceForAllItems
// Receives all items from the SplitInBatches "done" output,
// which aggregates every item that passed through the loop.

const items = $input.all();
const summary = {
  accounts_created: 0,
  accounts_updated: 0,
  accounts_error: 0,
  contacts_created: 0,
  contacts_updated: 0,
  contacts_error: 0,
  companies_synced: 0
};

for (const item of items) {
  const d = item.json;

  // Count company sync results
  if (d.sync_results?.company === 'synced') summary.companies_synced++;

  // Count account actions
  if (d.account_action === 'created') summary.accounts_created++;
  else if (d.account_action === 'updated') summary.accounts_updated++;
  else if (d.account_action?.includes('error')) summary.accounts_error++;

  // Count contact results
  for (const cr of (d.contact_results || [])) {
    if (cr.action === 'created') summary.contacts_created++;
    else if (cr.action === 'updated') summary.contacts_updated++;
    else if (cr.action?.includes('error')) summary.contacts_error++;
  }
}

summary.total_items = items.length;
console.log('Apollo Sync Summary:', JSON.stringify(summary));
return [{ json: summary }];
